import HTTPWSService, {WebSocketWithUrl} from './HTTPWSService';
import {ServiceOptions} from './index';
import Router = require("router");
import WebSocket = require('ws');
import http = require('http');

class HTTPSWSServiceDebug extends HTTPWSService {

    constructor(options:ServiceOptions, rootDir:string) {
        super('debuger-service', options, rootDir);
    }

    protected onMessage(command:any, client:WebSocketWithUrl):void {
        this.emit('message', command, client);
    }

    protected onClose(client:WebSocket):void {
        this.emit('close', client);
    }

    public onConnection(client:WebSocketWithUrl, request:http.IncomingMessage):void {
        super.onConnection(client, request);
        this.emit('connection', client);
    }

    public routes(url:Router) {
        super.routes(url);
        this.emit('routes', url);
    }
}

export default HTTPSWSServiceDebug;