import RemoteService from './RemoteService';
import WebSocket = require('ws');
import {Request} from 'jibo-client-framework';

export type CallbackHandler = (data:any) => void;
export interface Options {
    instanceId?:number;
    base:RemoteService;
    owner?:WebSocket; //If this object is not public this is the owner
}

abstract class ServiceRemoteObject {
    public static singeltonId:number;
    private static _messageId:number = 0;
    private static GLOBAL_COUNTER:number = 1000;

    public base:RemoteService;
    public owner:WebSocket;
    public name:string;
    public callee:WebSocket;

    protected _callbackHandlers:Map<number, CallbackHandler> = new Map<number, CallbackHandler>();
    public isDestroyed:boolean = false;

    private _instanceId:number;

    constructor(options:Options) {
        this._instanceId = options.instanceId !== undefined ?
            options.instanceId:
            ServiceRemoteObject.GLOBAL_COUNTER++;
        this.base = options.base;
        this.owner = options.owner;
        if(this.owner) {
            this.base.addInstance(this.owner, this);
        }
        else {
            this.base.addInstance(null, this);
        }
    }

    public get instanceId():number {
        return this._instanceId;
    }

    /**
     * Emits an event to the client object
     * @param  {string}        event   Event name
     * @param  {any[]}         ...args
     * @return {Promise<void>}
     */
    public emit(event:string, ...args:any[]) {
        let webSockets:WebSocket[] = [];
        if(this.owner) {
            webSockets.push(this.owner);
        }
        else {
            webSockets = this.base.connections;
        }
        let eventMessage:any = {
            type: 'event',
            instanceId: this._instanceId,
            methodName: 'emit',
            args: [event].concat(args)
        };
        eventMessage = JSON.stringify(eventMessage);
        webSockets.forEach((ws:WebSocket) => {
            this._sendMessage(ws, eventMessage);
        });
    }

    /**
     * Send a message to the client version of this object. Returns the result
     * of the RPC.
     * @param {string} methodName
     * @param {any[]} args
     */
    public async sendMessage<T>(methodName:string, args:any[], sendAndForget:boolean = false):Promise<T> {
        if(!this.owner) {
            throw new Error('Cannot send a message to a public remote object');
        }
        if(this.owner.readyState !== WebSocket.OPEN) {
            throw new Error('Owner Websocket is closed');
        }
        const request:Request = {
            type: 'request',
            messageId: this.getMessageId(),
            instanceId: this._instanceId,
            methodName,
            args,
            sendAndForget
        };
        this._sendMessage(this.owner, JSON.stringify(request));
        if(!sendAndForget) {
            return await this.waitForReply<T>(request.messageId);
        }
    }

    /**
     * Called when client that owns this object disconnects
     */
    public abstract destroy();

    /**
     * Removes this remote object from the remote service cache
     */
    protected remove() {
        this.base.cache.removeById(this.instanceId);
    }

    /**
     * When called with a specific messageId, this function will return
     * a Promise that resolves when a
     * @param messageId The message handle
     * @returns Promise that resolves to the return value
     */
    private waitForReply<T>(messageId:number):Promise<T> {
        return new Promise<T>((resolve:(ret:T) => void, reject) => {
            this.base.callbackHandlers.set(messageId, (value:T) => {
                resolve(value);
            });
            this.base.rejectionHandlers.set(messageId, (err) => {
                reject(err);
            });
        });
    }

    private getMessageId():number {
        return ServiceRemoteObject._messageId++;
    }

    private _sendMessage(ws:WebSocket, eventMessage:string) {
        if(ws.readyState === WebSocket.OPEN) {
            ws.send(eventMessage);
        }
    }
}

export default ServiceRemoteObject;
