import WebSocket = require('ws');
import {CacheManager} from 'jibo-cai-utils';
import {Reply, Request, MessageBase, MessageError} from 'jibo-client-framework';
import ServiceRemoteObject from './ServiceRemoteObject';
import HTTPWSService from './HTTPWSService';
import {ServiceOptions} from './index';

import parentLog from './log';
const log = parentLog.createChild('RemoteService');

interface MessageMap {
    reply:(ws:WebSocket, message:Reply) => void;
    request:(ws:WebSocket, message:Request) => void;
    error:(ws:WebSocket, message:MessageError) => void;
}

export type CallbackHandler = (data:any) => void;
export type RejectionHandler = (err) => void;

export class RemoteObjectCache extends CacheManager<ServiceRemoteObject, number, WebSocket> {}

abstract class RemoteService extends HTTPWSService {
    /** Maps a callback handle to a callback */
    public callbackHandlers:Map<number, CallbackHandler> = new Map<number, CallbackHandler>();
    public rejectionHandlers:Map<number, RejectionHandler> = new Map<number, RejectionHandler>();

    public cache:RemoteObjectCache = new RemoteObjectCache();
    protected lazyInitCheck: RejectionHandler;

    // /** Map of all instances that have been created. To map method calls to specific instances */
    // public instances:Map<number, ServiceRemoteObject> = new Map<number, ServiceRemoteObject>();
    //
    // /** Used to keep track of instances created on the request of a client for cleanup later */
    // public socketToInstances:Map<WebSocket, Set<ServiceRemoteObject>> = new Map<WebSocket, Set<ServiceRemoteObject>>();

    /** Maps incoming message type to a specific message type handler */
    private _messageMap:MessageMap;

    /**
     * @param  {string}         name      Name of the service in the registry
     * @param  {ServiceOptions} options
     * @param  {string}         staticDir Path to a static wenpage directory
     */
    constructor(name:string, options:ServiceOptions, staticDir:string) {
        super(name, options, staticDir);
        this.onConnection = this.onConnection.bind(this);
        this.onMessage = this.onMessage.bind(this);
        this._messageMap = {
            reply: this.onReply.bind(this),
            request: this.onRequest.bind(this),
            error: this.onError.bind(this)
        };
    }

    /**
     * When a client requests a remote instance be created the server
     * wants to associate that instance with the owner for cleanup
     * purposes. Called from the constructor of ServiceRemoteObject if
     * it's instantiated with an owner.
     * @param  {WebSocket}           owner    The client that owns the instance.
     * @param  {ServiceRemoteObject} instance The remote object instance
     */
    public addInstance(owner:WebSocket, instance:ServiceRemoteObject) {
        this.cache.addObjectToCache(instance, instance.instanceId, owner);
    }

    /**
     * When a websocket disconnects destory all instances that are associated
     * with this connection.
     * @param {WebSocket} client The client that disconnected.
     */
    protected onClose(client:WebSocket):void {
        const set:ServiceRemoteObject[] = this.cache.removeCache(client);
        set.forEach((instance:ServiceRemoteObject) => {
            instance.destroy();
            instance.isDestroyed = true;
        });
        this.emit('connection-closed', client);
    }

    /**
     * Called when a websocket message is received
     * @param  {any}       command [description]
     * @param  {WebSocket} ws      [description]
     */
    protected onMessage(command:any, ws:WebSocket) {
        const messageBase:MessageBase = command as MessageBase;
        if (this.lazyInitCheck) {
            this.lazyInitCheck(err => {
                if (!err) {
                    this._messageMap[messageBase.type](ws, messageBase);
                }
            });
        }
        else {
            this._messageMap[messageBase.type](ws, messageBase);
        }
    }

    /**
     * Called when the client sends a message reply. Finds the appropriate
     * callback handle and calls it with the results/
     * @param  {WebSocket} ws      Client that responded
     * @param  {Reply}     message The results
     */
    private onReply(ws:WebSocket, message:Reply) {
        if(this.callbackHandlers.has(message.messageId)) {
            this.callbackHandlers.get(message.messageId)(message.value);
            this.callbackHandlers.delete(message.messageId);
            this.rejectionHandlers.delete(message.messageId);
        }
    }

    /**
     * Called when the client sends an error. This happens when a remote
     * call threw an error or had an unhandled promise rejection.
     * @param  {WebSocket}      ws      Client that responded
     * @param  {MessageError}       message The results
     */
    private onError(ws:WebSocket, message:MessageError) {
        if(this.rejectionHandlers.has(message.messageId)) {
            this.rejectionHandlers.get(message.messageId)(message.message);
            this.callbackHandlers.delete(message.messageId);
            this.rejectionHandlers.delete(message.messageId);
        }
    }

    /**
     * Called when the client makes an RPC request on an instance
     * @param  {WebSocket} ws      The client making the request
     * @param  {Request}   message Contains the instance id, method and args
     */
    private async onRequest(ws:WebSocket, message:Request) {
        if (this.lazyInitCheck) {
            this.lazyInitCheck(err => {
                if (!err) {
                    this.doOnRequest(ws, message);
                }
            });
        }
        else {
            this.doOnRequest(ws, message);
        }
    }

    private async doOnRequest(ws:WebSocket, message:Request) {
        const instance = this.cache.getById(message.instanceId);

        try {
            if(!instance){
                throw new Error(`No instance with id "${message.instanceId}" available to handle method "${message.methodName}"`);
            }

            //useful to know what websocket called the method
            instance.callee = ws;
            if(!instance[message.methodName]) {
                throw new Error(`Cannot call method ${message.methodName} on class ${instance}`);
            }

            const ret = await instance[message.methodName].apply(instance, message.args);
            if(!message.sendAndForget) {
                const reply:Reply = {
                    type: 'reply',
                    messageId: message.messageId,
                    value: ret
                };
                if(ws.readyState === WebSocket.OPEN) {
                    ws.send(JSON.stringify(reply));
                }
            }
        }
        catch(err) {
            let messageText = 'Unspecified Error';
            if(err instanceof Error) {
                messageText = err.message;
            }
            else if(typeof err === 'string') {
                messageText = err;
            }
            const errorMessage:MessageError = {
                type: 'error',
                messageId: message.messageId,
                message: messageText
            };
            log.error(errorMessage);
            if(ws.readyState === WebSocket.OPEN) {
                ws.send(JSON.stringify(errorMessage));
            }
        }
    }
}

export default RemoteService;
