import HTTPService from './HTTPService';
import {ServiceOptions} from './index';
import Router = require('router');

class HTTPServiceDebug extends HTTPService {

    constructor(options:ServiceOptions, rootDir:string) {
        super('debugger-service', options, rootDir);
    }

    public routes(url:Router) {
        super.routes(url);
        //this.enableDebug();
	url.get('/testing/echo/:param1?/:param2?', (req, res) => {
            let reply = {
                params: req.params,
                query: req.query
            };
            this.sendJson(res, reply);
        });
    }
}

export default HTTPServiceDebug;
