import HTTPService from './HTTPService';
import parentLog from './log';
import {PromiseUtils} from 'jibo-cai-utils';
import {ServiceOptions} from './index';
import http = require('http');
import WebSocket = require('ws');

const log = parentLog.createChild('HTTPWSService');

export type WebSocketWithUrl = WebSocket & {url:string};

abstract class HTTPWSService extends HTTPService {

    public wsServer:WebSocket.Server;
    public connections:Array<WebSocket>;

    constructor(name:string, options:ServiceOptions, staticDir:string) {
        super(name, options, staticDir);
        this.onConnection = this.onConnection.bind(this);
        this.onMessage = this.onMessage.bind(this);
        this.onClose = this.onClose.bind(this);
        this.connections = [];
    }

    init(callback:(err?) => void):void {
        super.init((err) => {
            this.wsServer = new WebSocket.Server({server: this.server});
            this.wsServer.on('connection', this.onConnection);
            callback(err);
        });
    }

    onConnection(client:WebSocketWithUrl, request:http.IncomingMessage):void {
        client.url = request.url;
        client.on('close', () => this.closeClient(client));
        this.connections.push(client);
        client.on('message', (message:string) => {
            let command:any;
            try {
                command = JSON.parse(message);
            } catch (err) {
                return log.error('Error parsing message from socket', err);
            }
            this.onMessage(command, client);
        });
    }

    protected onClose(client:WebSocket):void {
        return;
    }

    protected abstract onMessage(command:any, client:WebSocketWithUrl):void;

    async sendWsJson(
        client: WebSocket,
        json: Object | string,
    ): Promise<boolean> {
        if (typeof json !== 'string') {
            try {
                json = JSON.stringify(json);
            }
            catch (err) {
                // Log stringify failures at error level, since there's likely
                // nothing the caller can do to recover gracefully, and it's
                // likely a logic error in the caller's code (object too
                // complex - will need a code change)
                log.error('Error stringifying json param:', err);
                return false;
            }
        }
        try {
            await PromiseUtils.promisify(cb => client.send(json, cb));
            return true;
        } catch (err) {
            // Log this situation at warn level, since we're going to resolve
            // false, so it's possible for the service to gracefully recover
            log.warn(`Error sending message; socket readyState ${client.readyState}:`, err);
            if (client.readyState === WebSocket.CLOSING || client.readyState === WebSocket.CLOSED) {
                this.closeClient(client);
            }
            return false;
        }
    }

    /**
     * Broadcast a message to all connected WebSocket clients
     * @method HTTPWSService#broadcast
     * @param {any} message JSON message to broadcast
     */
    public broadcast(message:any):void {
        log.debug(`broadcasting to ${this.connections.length} clients:`, message);
        this.connections.forEach(client => client.send(message));
    }

    private closeClient(client:WebSocket) {
        let i:number = this.connections.indexOf(client);
        if (i >= 0) {
            this.connections.splice(i, 1);
        }
        client.removeAllListeners();
        if (client.readyState !== client.CLOSED) {
            client.close();
        }
        this.onClose(client);
    }
}


export default HTTPWSService;
