/**
 * @class ServiceError
 * @param platformErrorKey {string} Platform error key expected by platform error services
 * @param value {ErrorValue} Value of error for platform key. See expected format below.
 * @description Format of error expected by errors service
 */
export class ServiceError {
    /*
     * @description the name of the error
     * @name ServiceError#key
     * @type {string}
     */
    public key:string;
    /*
     * @description Error value
     * @name ServiceError#value
     * @type {ErrorValue}
     */
    public value:ErrorValue;

    constructor(platformErrorKey:string, value:ErrorValue) {
        this.key = platformErrorKey;
        this.value = value;
    }
}

/**
 * @typedef ErrorType
 * @property UNKNOWN {number} Unknown error type.
 * @property EVENT {number} Event error type.
 * @property RECOVERABLE {number} Recoverable error type.
 * @description Types of errors to be reported
 */
export enum ErrorType {
    UNKNOWN = 0,
    EVENT = 1,
    RECOVERABLE = 2
}

/**
 * @typedef ErrorStatus
 * @property UNKNOWN {number} Unknown status.
 * @property BROKEN {number} Broken status.
 * @property FIXED {number} Fixed status.
 * @description Status of errors to be reported.
 */
export enum ErrorStatus {
    UNKNOWN = 0,
    BROKEN = 1,
    FIXED = 2
}

/**
 * @class ErrorValue
 * @param error {ErrorValue} an error to copy into this instance of ErrorValue
 * @description Value for each error expected by errors service
 */
export class ErrorValue {
    /*
     * @description name of the error
     * @name ErrorValue#name
     * @type {ErrorValue}
     */
    public name :string;
    /*
     * @description error type Unknown (0), Event (1), Recoverable (2)
     * @name ErrorValue#type
     * @type {ErrorValue}
     */
    public type :ErrorType;
    /*
     * @description error status Unknown (0), Broken (1), Fixed (2)
     * @name ErrorValue#status
     * @type {ErrorValue}
     */
    public status:ErrorStatus;
    /*
     * @description number of occurrences of this error
     * @name ErrorValue#count
     * @type {ErrorValue}
     */
    public count :number;
    /*
     * @description timestamp of the oldest occurrence of this error
     * @name ErrorValue#oldest
     * @type {ErrorValue}
     */
    public oldest:number[];
    /*
     * @description timestamp of the newest occurrence of this error
     * @name ErrorValue#newest
     * @type {Array<number>}
     */
    public newest:number[];

    constructor(name:string, type:ErrorType, status: ErrorStatus, count: number, oldest:number[], newest:number[]) {
        this.name = name;
        this.type = type;
        this.status = status;
        this.count = count;
        this.oldest = oldest;
        this.newest = newest;
    }
}

/**
 * @interface ServiceErrors
 * @description Format by which platform errors service expects an
 * array of errors to be reported.
 */
export class ServiceErrors {
    /*
     * @description Entires of the Service Errors
     * @name ServiceErrors#entries
     * @type {Array<ServiceError>}
     */
    public entries:ServiceError[];

    constructor(errors?:ServiceError[]) {
        this.entries = [];
        if(errors) {
            errors.forEach((err:ServiceError) => {
                this.entries.push(err);
            });
        }
    }
}